package com.hospital.management.controller.admission;import com.hospital.management.model.Admission;import com.hospital.management.service.*;import com.hospital.management.service.impl.AdmissionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions/view")public class AdmissionViewServlet extends HttpServlet{private final AdmissionService service;public AdmissionViewServlet(){this(new AdmissionServiceImpl());}public AdmissionViewServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));Admission a=id==null?null:service.getAdmission(id,AdmissionRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}q.setAttribute("admission",a);q.getRequestDispatcher("/WEB-INF/views/admissions/view.jsp").forward(q,r);}}
